#include <iostream>
#include <string_view>

enum Season
{
    spring = 0,
    summer = 1,
    autumn = 2,
    winter = 3
};

constexpr std::string_view seasonToStr(Season s)
{
    switch (s)
    {
        case spring: return "Spring";
        case summer: return "Summer";
        case autumn: return "Autumn";
        case winter: return "Winter";
        default:     return "Unknown";
    }
}

std::ostream& operator<<(std::ostream& out, Season s)
{
    out << seasonToStr(s);
    return out;
}

int main()
{
    int code{};
    std::cin >> code;

    Season s{ static_cast<Season>(code) };
    std::cout << "The season is " << s << '\n';

    return 0;
}

