#include <iostream>
#include <string_view>

enum Direction
{
    north = 0,
    east = 1,
    south = 2,
    west = 3,
    maxDirections = 4
};

constexpr std::string_view directionToStr(Direction d)
{
    switch (d)
    {
        case north: return "North";
        case east:  return "East";
        case south: return "South";
        case west:  return "West";
        default:    return "Invalid";
    }
}

std::ostream& operator<<(std::ostream& out, Direction d)
{
    out << directionToStr(d);
    return out;
}

std::istream& operator>>(std::istream& in, Direction& d)
{
    int input{};
    in >> input;

    if (input >= 0 && input < maxDirections)
        d = static_cast<Direction>(input);
    else
        d = maxDirections;

    return in;
}

int main()
{
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        Direction d{};
        std::cin >> d;
        std::cout << "Heading: " << d << '\n';
    }

    return 0;
}
